from dataclasses import dataclass, field
from datetime import date

@dataclass
class DecommissionRecord:
    service_name: str
    decommission_date: date
    data_inventory_completed_date: date
    legal_hold_consulted: bool
    legal_hold_active: bool
    deletion_plans: list["SecureDeletionPlan"] = field(default_factory=list)
    archived_data_locations: list[str] = field(default_factory=list)
    reviewed_by: str = ""   # legal / privacy officer name
    notes: str = ""

    def is_complete(self) -> bool:
        return (
            self.legal_hold_consulted
            and self.data_inventory_completed_date <= self.decommission_date
            and all(p.all_confirmed() for p in self.deletion_plans)
        )

    def compliance_status(self) -> str:
        issues = []
        if not self.legal_hold_consulted:
            issues.append("legal hold not consulted")
        if self.data_inventory_completed_date > self.decommission_date:
            issues.append("data inventory completed after decommission date")
        for p in self.deletion_plans:
            if not p.all_confirmed():
                issues.append(f"deletion not fully confirmed: {p.data_category}")
        if not self.reviewed_by:
            issues.append("no legal/privacy officer review recorded")
        if issues:
            return f"INCOMPLETE: {'; '.join(issues)}"
        return "COMPLIANT"

    def summary_report(self) -> str:
        lines = [
            f"Decommission record: {self.service_name}",
            f"  Decommission date: {self.decommission_date}",
            f"  Legal hold active: {self.legal_hold_active}",
            f"  Deletion plans: {len(self.deletion_plans)} categories",
            f"  Archived locations: {len(self.archived_data_locations)}",
            f"  Status: {self.compliance_status()}",
        ]
        return "\n".join(lines)

from dataclasses import dataclass, field
from enum import Enum

class DecommissionPhase(str, Enum):
    DATA_INVENTORY       = "data_inventory"
    LEGAL_REVIEW         = "legal_review"
    USER_NOTIFICATION    = "user_notification"   # if end-user data is being deleted
    RETENTION_EXECUTION  = "retention_execution" # archive / delete per policy
    DELETION_VERIFICATION = "deletion_verification"
    COMPLIANCE_SIGN_OFF  = "compliance_sign_off"
    INFRA_TEARDOWN       = "infra_teardown"
    POST_DECOMMISSION_AUDIT = "post_decommission_audit"

PHASE_ORDER = [
    DecommissionPhase.DATA_INVENTORY,
    DecommissionPhase.LEGAL_REVIEW,
    DecommissionPhase.USER_NOTIFICATION,
    DecommissionPhase.RETENTION_EXECUTION,
    DecommissionPhase.DELETION_VERIFICATION,
    DecommissionPhase.COMPLIANCE_SIGN_OFF,
    DecommissionPhase.INFRA_TEARDOWN,
    DecommissionPhase.POST_DECOMMISSION_AUDIT,
]

@dataclass
class PhaseStatus:
    phase: DecommissionPhase
    complete: bool = False
    owner: str = ""
    notes: str = ""

@dataclass
class DecommissionTimeline:
    service_name: str
    phases: list[PhaseStatus] = field(default_factory=lambda: [
        PhaseStatus(phase=p) for p in PHASE_ORDER
    ])

    def current_phase(self) -> DecommissionPhase | None:
        for status in self.phases:
            if not status.complete:
                return status.phase
        return None

    def can_proceed_to_infra_teardown(self) -> bool:
        data_phases = {
            DecommissionPhase.DATA_INVENTORY,
            DecommissionPhase.LEGAL_REVIEW,
            DecommissionPhase.RETENTION_EXECUTION,
            DecommissionPhase.DELETION_VERIFICATION,
            DecommissionPhase.COMPLIANCE_SIGN_OFF,
        }
        phase_map = {s.phase: s for s in self.phases}
        return all(phase_map[p].complete for p in data_phases)

    def gate_check(self) -> str:
        if not self.can_proceed_to_infra_teardown():
            incomplete = [
                p.value for p in [
                    DecommissionPhase.DATA_INVENTORY,
                    DecommissionPhase.LEGAL_REVIEW,
                    DecommissionPhase.RETENTION_EXECUTION,
                    DecommissionPhase.DELETION_VERIFICATION,
                    DecommissionPhase.COMPLIANCE_SIGN_OFF,
                ]
                if not {s.phase: s for s in self.phases}[p].complete
            ]
            return f"BLOCKED: complete these phases before infra teardown: {incomplete}"
        return "CLEARED: all data phases complete; infra teardown may proceed"
